INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e01e3ccd-560d-4e18-b769-47fb366198a3',
  '00000000-0000-0000-0000-000000000001',
  $escape$GitHub Actions Pipeline Design — Fail Fast with lint → test → build → deploy$escape$,
  $escape$Structure your GitHub Actions workflows so expensive jobs never run when cheap ones fail. Use `needs` to enforce strict job ordering and set `fail-fast: true` on matrix strategies to cancel sibling jobs immediately on failure.

Lint runs first — it's the cheapest gate. Use `actions/setup-node` with a cached `node_modules` and run ESLint/Prettier checks before any test runner spins up. If lint fails, the `test` job never queues. Tests follow: split unit and integration into separate jobs under `needs: [lint]` so they parallelize. The `build` job declares `needs: [test]` — it only runs once all test shards pass.

For deploy, gate on `needs: [build]` and add a condition like `if: github.ref == 'refs/heads/main'` so feature branches never touch production. Use `environment: production` to enforce required reviewers via GitHub's Environment Protection Rules — this is a native guardrail, not a script hack.

Upload build artifacts with `actions/upload-artifact` in the build job and download them in deploy — never rebuild in the deploy stage.$escape$,
  $escape$jobs:
  lint:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - uses: actions/setup-node@v4
        with:
          node-version: 22
          cache: npm
      - run: npm ci && npm run lint

  test:
    needs: [lint]
    runs-on: ubuntu-latest
    strategy:
      fail-fast: true
      matrix:
        shard: [1, 2, 3]
    steps:
      - uses: actions/checkout@v4
      - run: npm ci && npm test -- --shard=${{ matrix.shard }}/3

  build:
    needs: [test]
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - run: npm ci && npm run build
      - uses: actions/upload-artifact@v4
        with:
          name: dist
          path: dist/

  deploy:
    needs: [build]
    runs-on: ubuntu-latest
    environment: production
    if: github.ref == 'refs/heads/main'
    steps:
      - uses: actions/download-artifact@v4
        with:
          name: dist
      - run: ./scripts/deploy.sh$escape$,
  $escape$bash$escape$,
