INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e7d5088a-bd7a-4b26-87ee-cdb00ece7c36',
  '00000000-0000-0000-0000-000000000001',
  $escape$GitHub Actions — Reusable Workflows vs Composite Actions: Pick the Right Abstraction$escape$,
  $escape$When DRYing up GitHub Actions pipelines, developers often reach for reusable workflows and composite actions interchangeably — but they serve different scopes. A reusable workflow (`workflow_call` trigger) runs as its own job graph, inheriting secrets via `secrets: inherit` and supporting matrix strategies. It's ideal for entire CI pipelines you want to share across repos. A composite action (`using: composite` in `action.yml`) bundles steps inside a single job, sharing the runner context, environment variables, and workspace with the calling job — ideal for step-level reuse like setup, linting, or artifact upload. Key gotcha: composite actions can't use `needs:` or define their own job-level `permissions`. Reusable workflows can, but they can't directly access the caller's `env` context — only `inputs` and `secrets`. For monorepos, composite actions win on speed (no extra job spin-up). For cross-repo standardization of full pipelines, reusable workflows are the right call. Mix both: a reusable workflow that internally calls composite actions for its steps.$escape$,
  $escape$# .github/workflows/ci.yml — calling a reusable workflow
jobs:
  test:
    uses: my-org/.github/.github/workflows/run-tests.yml@main
    with:
      node-version: '20'
    secrets: inherit

  lint:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      # composite action for step-level reuse
      - uses: my-org/.github/actions/setup-node@main
        with:
          node-version: '20'
      - run: npm run lint$escape$,
