INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '951fb600-dfb4-4312-b80f-6d977a514e06',
  '00000000-0000-0000-0000-000000000001',
  $escape$GitHub Actions + ArgoCD — GitOps Sync Policies and the App of Apps Pattern$escape$,
  $escape$In a GitOps workflow, GitHub Actions owns the write side: it builds your image, bumps the tag in your config repo, and commits — ArgoCD owns the read side, continuously reconciling cluster state with that repo. The critical detail is the separation: your app repo triggers the Actions workflow; the workflow writes to a separate config repo; ArgoCD watches only the config repo.

Sync policies control how ArgoCD reacts to those commits. `automated.selfHeal: true` re-syncs if someone manually patches the cluster. `automated.prune: true` deletes resources removed from Git — dangerous without testing. Leave prune off in staging until your manifests are clean.

The app of apps pattern solves bootstrapping at scale. A root Application points to a directory of Application manifests. Your GitHub Actions workflow updates child app image tags; the root app syncs first and creates/updates children automatically. One ArgoCD install governs every environment. Use a matrix strategy in Actions — one job per environment — each committing to an environment-scoped path (`envs/prod/`, `envs/staging/`) that a dedicated child Application watches.$escape$,
  $escape$# .github/workflows/deploy.yml
jobs:
  gitops-push:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
        with:
          repository: myorg/config-repo
          token: ${{ secrets.CONFIG_REPO_PAT }}
          path: config

      - name: Bump image tag
        run: |
          sed -i "s|tag: .*|tag: ${{ github.sha }}|" \
            config/envs/${{ matrix.env }}/values.yaml

      - name: Commit and push
        run: |
          cd config
          git config user.email "ci@myorg.com"
          git config user.name "GitHub Actions"
          git commit -am "chore: bump ${{ matrix.env }} to ${{ github.sha }}"
          git push$escape$,
  $escape$bash$escape$,
