INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '254f8195-5fe7-4396-a293-9ea1d5d0011a',
  '00000000-0000-0000-0000-000000000001',
  $escape$GitHub Actions Build Artifacts — Version, Store, and Promote Without Rebuilding$escape$,
  $escape$GitHub Actions artifacts are the promotion primitive between your build and deploy stages. Use `actions/upload-artifact@v4` with a version string built from `github.run_number` and the short SHA — this gives you sortable, traceable names with no external registry.

Pass the version downstream via `jobs.<id>.outputs` so every subsequent job downloads the exact same artifact. Never rebuild in a deploy job; download and ship. The `needs.<job>.outputs.version` pattern creates an auditable promotion chain: build → staging → prod, one artifact, zero rebuilds.

Control retention by branch: 90 days for `main`, 7 for pull requests. The `workflow_run` trigger lets a separate release workflow download artifacts from a completed CI workflow without coupling the two pipelines.

In v4, `merge-multiple: true` on `download-artifact` flattens outputs from matrix builds into one directory — critical when you're packaging multi-arch binaries. Combine this with a `needs` fan-in job that assembles and re-uploads a single versioned archive before promotion begins.$escape$,
  $escape$build:
  runs-on: ubuntu-latest
  outputs:
    version: ${{ steps.ver.outputs.tag }}
  steps:
    - uses: actions/checkout@v4
    - id: ver
      run: echo "tag=${{ github.run_number }}-${GITHUB_SHA::7}" >> "$GITHUB_OUTPUT"
    - run: npm ci && npm run build
    - uses: actions/upload-artifact@v4
      with:
        name: app-${{ steps.ver.outputs.tag }}
        path: dist/
deploy-staging:
  needs: build
  steps:
    - uses: actions/download-artifact@v4
      with:
        name: app-${{ needs.build.outputs.version }}$escape$,
  $escape$bash$escape$,
