INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b82fd7b3-25e7-4925-a1f6-f9b6d10903af',
  '00000000-0000-0000-0000-000000000001',
  $escape$GitHub Actions Rollback Strategy — Automated Redeploy on Failed Deploy$escape$,
  $escape$When a deployment job fails, GitHub Actions can automatically trigger a rollback by chaining jobs with `needs` and `if` conditions. The pattern: run your deploy job, then define a `rollback` job that only executes when the deploy job fails (`if: failure()`). Inside the rollback job, use the GitHub CLI (`gh`) or the REST API to fetch the last successful deployment SHA via `gh api repos/{owner}/{repo}/deployments` filtered by `environment` and `state=success`. Once you have the SHA, re-trigger your deploy workflow using `gh workflow run` with that SHA as an input. For zero-downtime rollbacks on container-based deploys, store the previous image tag as a GitHub Actions variable using `gh variable set LAST_GOOD_TAG` at the end of each successful deploy. The rollback job then reads `${{ vars.LAST_GOOD_TAG }}` directly. Combine this with `deployment_status` event listeners to sync rollback state back to GitHub Environments, keeping your deployment history accurate and audit-ready.$escape$,
  $escape$jobs:
  deploy:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - run: ./scripts/deploy.sh
      - if: success()
        run: gh variable set LAST_GOOD_TAG --body "${{ github.sha }}"
        env:
          GH_TOKEN: ${{ secrets.GITHUB_TOKEN }}

  rollback:
    needs: deploy
    if: failure()
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
        with:
          ref: ${{ vars.LAST_GOOD_TAG }}
      - run: ./scripts/deploy.sh
        env:
          GH_TOKEN: ${{ secrets.GITHUB_TOKEN }}$escape$,
  $escape$bash$escape$,
