INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9fd494a7-a4ae-42a5-a403-affc825177e7',
  '00000000-0000-0000-0000-000000000001',
  $escape$GitHub Actions Preview Environments — Ephemeral Deployments Per PR, Gone on Merge$escape$,
  $escape$Every pull request gets its own live environment using two GitHub Actions workflows: one triggered on `pull_request` (types: `[opened, synchronize, reopened]`) to deploy, and one on `pull_request` (types: `[closed]`) to tear down. The deploy workflow uses `github.event.pull_request.number` to namespace resources — e.g., `preview-pr-${{ github.event.number }}` — so environments never collide. Post-deployment, `actions/github-script` writes the preview URL back as a PR comment using `octokit.rest.issues.createComment`. On merge or close, the teardown workflow runs regardless of merge outcome by listening to the `closed` event type, which fires for both merged and abandoned PRs. Use GitHub Environments (`environment: preview-pr-${{ github.event.number }}`) with `auto-inactivate-deployments: true` so the Deployments tab stays clean. Store per-PR state (resource IDs, URLs) in environment-scoped secrets or output them to a GitHub Environment variable via `gh variable set`. Combine with `concurrency: group: pr-${{ github.event.number }}` to cancel in-flight deploys when a new push arrives mid-review.$escape$,
  $escape$name: Preview Deploy
on:
  pull_request:
    types: [opened, synchronize, reopened, closed]

jobs:
  deploy:
    if: github.event.action != 'closed'
    runs-on: ubuntu-latest
    environment:
      name: preview-pr-${{ github.event.number }}
      url: https://pr-${{ github.event.number }}.preview.example.com
    concurrency:
      group: pr-${{ github.event.number }}
      cancel-in-progress: true
    steps:
      - uses: actions/checkout@v4
      - name: Deploy preview
        run: ./scripts/deploy.sh --env pr-${{ github.event.number }}
      - name: Comment URL
        uses: actions/github-script@v7
        with:
          script: |
            github.rest.issues.createComment({
              issue_number: context.issue.number,
              owner: context.repo.owner,
              repo: context.repo.repo,
              body: `Preview: https://pr-${{ github.event.number }}.preview.example.com`
            })

  teardown:
    if: github.event.action == 'closed'
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - run: ./scripts/destroy.sh --env pr-${{ github.event.number }}$escape$,
  $escape$bash$escape$,
