INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd04ef757-b209-4ae9-b370-d53c7ddccd00',
  '00000000-0000-0000-0000-000000000001',
  $escape$GitHub Actions Security Pipeline — SAST, Dependency & Container Scanning$escape$,
  $escape$Shift security left by layering three scanning jobs in a single GitHub Actions workflow. For SAST, CodeQL runs as a reusable action — `github/codeql-action/analyze@v3` — with language auto-detection and uploads results to the Security tab via SARIF. For dependency scanning, Dependabot handles automated PRs, but for blocking CI, use `actions/dependency-review-action@v4` on pull_request events; it diffs the dependency graph between base and head SHAs and fails on CVSS score thresholds you control via `fail-on-severity`. For container images, `anchore/scan-action@v4` wraps Grype under the hood — point it at your built image digest, set `fail-build: true`, and pipe the SARIF output to `github/codeql-action/upload-sarif@v3` so findings surface in the same Security tab. Run all three as parallel jobs under a `security` workflow triggered on push to main and on every PR. Gate merges with a required status check on the `security` workflow to enforce zero-critical policy without slowing feature branches.$escape$,
  $escape$jobs:
  codeql:
    uses: github/codeql-action/init@v3
    with:
      languages: javascript, python

  dependency-review:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - uses: actions/dependency-review-action@v4
        with:
          fail-on-severity: high

  container-scan:
    runs-on: ubuntu-latest
    steps:
      - uses: anchore/scan-action@v4
        with:
          image: ${{ env.IMAGE_DIGEST }}
          fail-build: true
          severity-cutoff: critical
      - uses: github/codeql-action/upload-sarif@v3
        with:
          sarif_file: results.sarif$escape$,
  $escape$bash$escape$,
