INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e7dfc669-03d4-4fc4-aa0a-c45008f54aba',
  '00000000-0000-0000-0000-000000000001',
  $escape$GitHub Actions — Failure Alerts, Status Badges, and Incident Escalation$escape$,
  $escape$When a GitHub Actions workflow fails, silence is the enemy. Wire up `if: failure()` steps to push Slack or PagerDuty alerts directly from your workflow using `curl` against their APIs — no third-party Actions required. Use `github.run_url` from the `github` context to embed a deep link to the failed run inside every alert payload, so on-call engineers land directly on the logs. For status badges, GitHub generates them automatically at `https://github.com/{owner}/{repo}/actions/workflows/{workflow-file}.yml/badge.svg` — pin these to your README with a branch filter (`?branch=main`) to reflect production health at a glance. For multi-stage pipelines, use `needs` context and `result == 'failure'` conditions on a dedicated `notify` job that aggregates failures across matrix jobs before escalating, preventing duplicate pages. Combine `GITHUB_STEP_SUMMARY` with `>> $GITHUB_STEP_SUMMARY` to write structured Markdown incident summaries directly into the workflow run UI, giving responders context without leaving GitHub.$escape$,
  $escape$notify-on-failure:
  runs-on: ubuntu-latest
  needs: [build, test, deploy]
  if: failure()
  steps:
    - name: Send PagerDuty alert
      run: |
        curl -X POST https://events.pagerduty.com/v2/enqueue \
          -H 'Content-Type: application/json' \
          -d '{
            "routing_key": "'${{ secrets.PD_ROUTING_KEY }}'",
            "event_action": "trigger",
            "payload": {
              "summary": "CI failure on ${{ github.ref_name }}: ${{ github.run_url }}",
              "severity": "critical",
              "source": "github-actions"
            }
          }'$escape$,
  $escape$bash$escape$,
